return items.map(item => {
  const d = item.json;

  const num = (v) => {
    if (v === null || v === undefined || v === '') return null;
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  };

  const bool1 = (v) => num(v) === 1;

  const strOrNull = (v) => {
    const s = (v ?? '').toString().trim();
    return s ? s : null;
  };

  const titleStr = (d.title ?? '').toString();
  const titleNorm = titleStr.trim().toUpperCase();

  // marker for "GOODMORNING" posts (text will be taken from COOP_FACT later in Expand per store)
  const isGoodMorning = titleNorm === 'GOODMORNING';

  return {
    json: {
      id: num(d.id),
      status: num(d.status),
      region: num(d.region),
      post_type: num(d.post_type),

      send_tg: bool1(d.send_tg),
      send_max: bool1(d.send_max),
      send_vk: bool1(d.send_vk),
      send_site: bool1(d.send_site),

      // debug flag for telegram routing (1 = send to test channel)
      tg_debug: num(d.tg_debug),

      title: titleStr,

      // plain text (fallback)
      text: d.text ?? '',

      // ✅ formatted HTML from Google Sheets (after merge)
      text_html: strOrNull(d.text_html),

      // 1 = HTML, 2 = MarkdownV2, else = fallback safe HTML later
      parse_mode: num(d.parse_mode) ?? 0,

      media_raw: d.media_url ?? '',

      // NEW: raw order link (format "Button title|https://...")
      order_link: strOrNull(d.order_link),

      // NEW: TG invite experiment flag (if empty -> add invite footer later)
      tg_inv_expt: strOrNull(d.tg_inv_expt),

      // старая логика: ссылка на бота (формат "197_КУПИТЬ")
      old_post: strOrNull(d.old_post),

      all_region: bool1(d.all_region),
      points_note_mode:
        d.points_note_mode === '' || d.points_note_mode === null || d.points_note_mode === undefined
          ? null
          : (num(d.points_note_mode) ?? null),

      schedule: strOrNull(d.schedule),
      publish_at: strOrNull(d.publish_at),

      // service fields
      last_run_at_utc: strOrNull(d.last_run_at_utc),
      last_run_at: strOrNull(d.last_run_at),
      last_run_key: strOrNull(d.last_run_key),

      error: strOrNull(d.error),

      // flag for downstream logic
      _goodmorning: isGoodMorning,

      // исходная строка целиком (включая колонки точек)
      _raw: d,
    },
  };
});

// === НАСТРОЙКИ ===
const TG_TEST_CHAT_ID = '-1003640743827';
const TG_TEST_FORCE_AUTH_TYPE_1 = true; // true => order_link, false => old_post

// !!! Поставьте реальные имена узлов:
const FILTER_NODE_NAME = 'Filter1';
const POSTGRES_NODE_NAME = 'Postgre_store_extract';
const COOP_FACT_NODE_NAME = 'GS_CoopFact_GetRows'; // NEW

// Telegram deep-link base
const TG_OLD_BOT_BASE = 'https://t.me/kooptorg3_start_bot?start=';

function regionToStoreTz(region) {
  if (Number(region) === 54) return 7;
  if (Number(region) === 82) return 3;
  return null;
}

function regionToTzName(region) {
  if (Number(region) === 54) return 'Asia/Novosibirsk';
  if (Number(region) === 82) return 'Europe/Simferopol';
  return 'Europe/Moscow';
}

function escapeHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// минимально достаточное экранирование MarkdownV2
function escapeMarkdownV2(s) {
  // Telegram MarkdownV2 special chars: _ * [ ] ( ) ~ ` > # + - = | { } . !
  return String(s ?? '').replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&');
}
// Telegram HTML supports a limited subset and DOES NOT support <br>. Convert it to newlines.
function normalizeTelegramHtml(html) {
  if (html === null || html === undefined) return '';

  let s = String(html);

  // <br> / <br/> / <br /> -> newline
  s = s.replace(/<br\s*\/?>/gi, '\n');

  // Convert common block tags to newlines (open tags removed, close tags -> newline)
  s = s.replace(/<\/(p|div|h\d|blockquote)>/gi, '\n');
  s = s.replace(/<(p|div|h\d|blockquote)(\s[^>]*)?>/gi, '');

  // Optionally strip spans (sometimes produced by HTML converters)
  s = s.replace(/<\/?span(\s[^>]*)?>/gi, '');

  // Minimal entity cleanup
  s = s.replace(/&nbsp;/gi, ' ');

  // Cleanup excessive newlines
  s = s.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  s = s.replace(/\n{3,}/g, '\n\n').trim();

  return s;
}


function buildTgTextAndMode(post) {
  const pm = Number(post.parse_mode);

  // Plain text from sheet (fallback)
  const textPlain = (post.text ?? '').toString();

  // Formatted HTML from sheet (after Merge text_html into rows)
  const textHtml = (post.text_html ?? '').toString();

  if (pm === 2) {
    // MarkdownV2: use plain text
    return { text: textPlain, parse_mode: 'MarkdownV2' };
  }

  if (pm === 1) {
    // HTML: prefer formatted text_html if present, but normalize for Telegram (no <br>, limited tags)
    const tRaw = (textHtml && textHtml.trim()) ? textHtml : textPlain;
    const t = normalizeTelegramHtml(tRaw);
    return { text: t, parse_mode: 'HTML' };
  }

  // Fallback: safe HTML (escape)
  return { text: escapeHtml(textPlain), parse_mode: 'HTML' };
}

// old_post format: "197_КУПИТЬ"
function parseOldPost(oldPostValue) {
  const raw = (oldPostValue ?? '').toString().trim();
  if (!raw) return null;

  const m = raw.match(/^(\d{3})_(.+)$/);
  if (!m) return null;

  const oldId = m[1];
  const label = (m[2] ?? '').toString().trim();
  if (!label) return null;

  return { old_id: oldId, label: label.toUpperCase() };
}

function formatDDMMYYYYInTz(dateUtc, tzName) {
  const parts = new Intl.DateTimeFormat('en-GB', {
    timeZone: tzName,
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
  }).formatToParts(dateUtc);

  const map = {};
  for (const p of parts) if (p.type !== 'literal') map[p.type] = p.value;

  return `${map.day}${map.month}${map.year}`;
}

// YYYY-MM-DD in TZ from UTC date
function formatYYYYMMDDInTz(dateUtc, tzName) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: tzName,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(dateUtc);

  const map = {};
  for (const p of parts) if (p.type !== 'literal') map[p.type] = p.value;

  return `${map.year}-${map.month}-${map.day}`;
}

function buildOldLink({ old_id, label }, storeId, datePart, parseMode) {
  const sid = String(storeId ?? '').trim();
  if (!sid) return null;

  // шаблон как в твоём примере: webapp_<oldId><DDMMYYYY><storeId>_<storeId>
  const startParam = `webapp_${old_id}${datePart}${sid}_${sid}`;
  const url = `${TG_OLD_BOT_BASE}${startParam}`;

  if (parseMode === 'MarkdownV2') {
    const textMd = escapeMarkdownV2(label);
    // URL в MarkdownV2 лучше тоже экранировать минимум (скобки и т.п.)
    const urlMd = url.replace(/\)/g, '\\)').replace(/\(/g, '\\(');
    return `[${textMd}](${urlMd})`;
  }

  // HTML
  const textHtml = escapeHtml(label);
  const urlHtml = escapeHtml(url);
  return `<a href="${urlHtml}">${textHtml}</a>`;
}

function appendOldLinkToText(text, oldLink) {
  const base = (text ?? '').toString();
  if (!oldLink) return base;
  if (!base.trim()) return oldLink;
  return `${base}\n\n${oldLink}`;
}

// --- Invite footer helpers ---
function cleanUrl(v) {
  const s = String(v ?? '').trim();
  return s ? s : null;
}

function buildLinkLabel(label, url, parseMode) {
  if (!url) return null;

  if (parseMode === 'MarkdownV2') {
    const t = escapeMarkdownV2(label);
    const u = String(url).replace(/\)/g, '\\)').replace(/\(/g, '\\(');
    return `[${t}](${u})`;
  }

  // HTML
  return `<a href="${escapeHtml(url)}">${escapeHtml(label)}</a>`;
}

// UPDATED: labels without "на канал"
function buildInviteFooter(parseMode, tgUrl, maxUrl) {
  const lines = [];

  const tgLine = buildLinkLabel('📢 Подпишись в Telegram', tgUrl, parseMode);
  if (tgLine) lines.push(tgLine);

  const maxLine = buildLinkLabel('⚡ Подпишись в MAX', maxUrl, parseMode);
  if (maxLine) lines.push(maxLine);

  return lines.length ? lines.join('\n') : null;
}

function appendFooter(text, footer) {
  const base = (text ?? '').toString();
  if (!footer) return base;
  if (!base.trim()) return footer;
  return `${base}\n\n${footer}`;
}

// --- Order links as TEXT block (for Telegram post_auth_type=1) ---
function buildOrderLinksText(orderLinks, parseMode) {
  if (!Array.isArray(orderLinks) || orderLinks.length === 0) return null;

  const lines = [];
  for (const b of orderLinks) {
    const t = cleanLine(b?.text);
    const u = cleanLine(b?.url);
    if (!t || !u) continue;

    let link = buildLinkLabel(t, u, parseMode);
    if (!link) continue;

    // Make order_links bold in Telegram
    if (parseMode === 'MarkdownV2') {
      link = `**${link}**`;
    } else {
      // HTML
      link = `<b>${link}</b>`;
    }

    lines.push(`• ${link}`);
  }

  return lines.length ? lines.join('\n') : null;
}

function appendOrderLinksToText(text, orderLinks, parseMode) {
  const base = (text ?? '').toString();
  const block = buildOrderLinksText(orderLinks, parseMode);
  if (!block) return base;
  if (!base.trim()) return block;
  return `${base}\n\n${block}`;
}

// Ваш формат: store_195_Большевистская
function pickStoreIdsFromRaw(raw) {
  const ids = [];
  for (const [k, v] of Object.entries(raw || {})) {
    const key = String(k ?? '').trim();
    const m = key.match(/^store_(\d+)_/); // строго ваш формат
    if (!m) continue;

    const storeId = Number(m[1]);
    if (!Number.isFinite(storeId)) continue;

    const vv = (v ?? '').toString().trim();
    if (vv === '1') ids.push(storeId);
  }
  return ids;
}

function cleanLine(s) {
  return String(s ?? '')
    .replace(/[\uFEFF\u200B\u200C\u200D\u2060\u00AD]/g, '')
    .trim();
}

function parseOrderLinks(orderLinkRaw) {
  const raw = (orderLinkRaw ?? '').toString();
  const lines = raw.split(/\r\n|\n|\r/g).map(cleanLine).filter(Boolean);

  const out = [];
  for (const line of lines) {
    // Format: Button text|https://...
    const parts = line.split('|');
    if (parts.length < 2) continue;

    const text = cleanLine(parts[0]);
    const url = cleanLine(parts.slice(1).join('|')); // keep '|' inside URL if any

    if (!text || !url) continue;

    // minimal url sanity check
    if (!/^https?:\/\//i.test(url)) continue;

    out.push({ text, url });
  }

  return out.length ? out : null;
}

/**
 * media_raw format (each line):
 *   ф|https://...
 *   в|https://...
 * returns [{type:'photo'|'video', media:'url'}]
 */
function parseMediaLines(mediaRaw) {
  const raw = (mediaRaw ?? '').toString();
  const lines = raw.split(/\r\n|\n|\r/g).map(cleanLine).filter(Boolean);

  const out = [];
  for (const line of lines) {
    const m = line.match(/^([фв])\|(.*)$/i);
    if (!m) continue;

    const kind = m[1].toLowerCase();
    const url = cleanLine(m[2] || '');
    if (!url) continue;

    out.push({
      type: kind === 'ф' ? 'photo' : 'video',
      media: url,
    });
  }
  return out;
}

function isCaptionOk(text) {
  const t = (text ?? '').toString();
  // caption limit ~1024; keep margin
  return t.length > 0 && t.length <= 950;
}

// NEW: normalize COOP_FACT date to YYYY-MM-DD (supports 04/01/2026)
function normalizeFactDate(v) {
  const s = cleanLine(v);
  if (!s) return null;

  // YYYY-MM-DD
  let m = s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (m) return `${m[1]}-${m[2]}-${m[3]}`;

  // DD.MM.YYYY
  m = s.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;

  // DD/MM/YYYY  (your format: 04/01/2026)
  m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) {
    const dd = Number(m[1]);
    const mm = Number(m[2]);
    const yyyy = Number(m[3]);
    if (dd >= 1 && dd <= 31 && mm >= 1 && mm <= 12) {
      const dds = String(dd).padStart(2, '0');
      const mms = String(mm).padStart(2, '0');
      return `${yyyy}-${mms}-${dds}`;
    }
  }

  // Try Date.parse for ISO-ish values (not reliable for 04/01/2026, but ok for other strings)
  const t = Date.parse(s);
  if (!Number.isNaN(t)) {
    const d = new Date(t);
    const y = d.getUTCFullYear();
    const mo = String(d.getUTCMonth() + 1).padStart(2, '0');
    const da = String(d.getUTCDate()).padStart(2, '0');
    return `${y}-${mo}-${da}`;
  }

  return null;
}

// get publish date (YYYY-MM-DD) in region TZ for GOODMORNING
function getGoodMorningDateKey(post, tzName) {
  // Prefer _occurrence_utc (for recurring). For one-time it will also be present in your Determine due.
  const occIso = cleanLine(post._occurrence_utc);
  if (occIso) {
    const d = new Date(occIso);
    if (!Number.isNaN(d.getTime())) return formatYYYYMMDDInTz(d, tzName);
  }

  // Fallback: parse from _occurrence_local / _publish_at_parsed (strings like "YYYY-MM-DD ... (TZ)")
  const s1 = cleanLine(post._occurrence_local);
  if (s1) {
    const m = s1.match(/^(\d{4}-\d{2}-\d{2})\b/);
    if (m) return m[1];
  }

  const s2 = cleanLine(post._publish_at_parsed);
  if (s2) {
    const m = s2.match(/^(\d{4}-\d{2}-\d{2})\b/);
    if (m) return m[1];
  }

  // Last resort: if publish_at exists as "YYYY-MM-DD ..." without TZ
  const s3 = cleanLine(post.publish_at);
  if (s3) {
    const m = s3.match(/^(\d{4}-\d{2}-\d{2})\b/);
    if (m) return m[1];
  }

  return null;
}

// --- Забираем данные по имени узлов ---
const postsInput = $items(FILTER_NODE_NAME).map(x => x.json);
const storesInput = $items(POSTGRES_NODE_NAME).map(x => x.json);
const factsInput = $items(COOP_FACT_NODE_NAME).map(x => x.json);

// Build facts map: YYYY-MM-DD -> fact
const factMap = new Map();
for (const row of factsInput) {
  const dk = normalizeFactDate(row?.date);
  const fact = cleanLine(row?.fact);
  if (!dk || !fact) continue;
  factMap.set(dk, row.fact); // keep last
}

// Диагностика stores
const tzSet = new Set();
for (const s of storesInput) {
  if (s && s.time_zone !== undefined && s.time_zone !== null && s.time_zone !== '') {
    tzSet.add(String(s.time_zone));
  }
}
const storesDebug = {
  stores_count: storesInput.length,
  stores_time_zones: Array.from(tzSet).sort(),
  stores_first_keys: storesInput[0] ? Object.keys(storesInput[0]) : [],
  facts_count: factsInput.length,
  facts_keys_sample: Array.from(factMap.keys()).slice(0, 10),
};

// Если stores не пришли — вернём ошибку на каждый пост
if (storesInput.length === 0) {
  return postsInput.map(post => ({
    json: {
      ...post,
      // NEW
      order_links: parseOrderLinks(post.order_link ?? post._raw?.order_link),
      _tg_targets_empty: true,
      _tg_targets_reason: `stores input is empty: $items("${POSTGRES_NODE_NAME}") returned 0 rows`,
      _stores_debug: storesDebug,

      // важные служебные поля для дальнейшего апдейта Sheets
      row_number: post?._raw?.row_number ?? null,
      _now: post._now ?? null,
      _now_utc: post._now_utc ?? null,
      _run_key: post._run_key ?? null,
    },
  }));
}

// Map store_id -> storeRow
const storeMap = new Map();
for (const s of storesInput) {
  const storeId = Number(s.store_id);
  if (!Number.isFinite(storeId)) continue;
  if (!storeMap.has(storeId)) storeMap.set(storeId, s);
}

const out = [];

for (const post of postsInput) {
  const hasAnyChannel = Boolean(post.send_tg || post.send_max || post.send_vk || post.send_site);
  if (!hasAnyChannel) continue;

  // --- протаскиваем row_number (для Update в Sheets) ---
  const rowNumber = post?._raw?.row_number ?? null;

  // --- протаскиваем служебные поля запуска (для last_run_*) ---
  const nowLocal = post._now ?? null;      // локальное время региона (строка)
  const nowUtcIso = post._now_utc ?? null; // ISO UTC
  const runKey = post._run_key ?? null;

  // --- GOODMORNING text override from COOP_FACT (общий, меняем post.text) ---
  const tzName = regionToTzName(post.region);
  let postForText = post;

  if (post._goodmorning === true) {
    const dateKey = getGoodMorningDateKey(post, tzName);
    const fact = dateKey ? factMap.get(dateKey) : null;

    if (!dateKey) {
      out.push({
        json: {
          ...post,
          // NEW
          order_links: parseOrderLinks(post.order_link ?? post._raw?.order_link),
          row_number: rowNumber,
          _now: nowLocal,
          _now_utc: nowUtcIso,
          _run_key: runKey,

          _prepare_error: `GOODMORNING: cannot determine date key from occurrence/publish fields`,
          _goodmorning_date_key: null,
          _stores_debug: storesDebug,
        },
      });
      continue;
    }

    if (!fact || !cleanLine(fact)) {
      out.push({
        json: {
          ...post,
          // NEW
          order_links: parseOrderLinks(post.order_link ?? post._raw?.order_link),
          row_number: rowNumber,
          _now: nowLocal,
          _now_utc: nowUtcIso,
          _run_key: runKey,

          _prepare_error: `GOODMORNING: no fact found for date=${dateKey} in COOP_FACT`,
          _goodmorning_date_key: dateKey,
          _stores_debug: storesDebug,
        },
      });
      continue;
    }

    postForText = {
      ...post,
      text: `${fact}\n!!Навигация`,
      _goodmorning_date_key: dateKey,
    };
  }
  // --- /GOODMORNING ---

  const needTg = Boolean(postForText.send_tg);
  const needMax = Boolean(postForText.send_max);

  // NEW: parse order links (multi-line: Text|URL)
  const order_links = parseOrderLinks(postForText.order_link ?? postForText._raw?.order_link);

  // === Если TG/MAX не нужны — просто пробрасываем item дальше (для VK/SITE) ===
  if (!needTg && !needMax) {
    out.push({
      json: {
        ...postForText,

        // NEW
        order_links,

        row_number: rowNumber,
        _now: nowLocal,
        _now_utc: nowUtcIso,
        _run_key: runKey,
        _stores_debug: storesDebug,
      },
    });
    continue;
  }

  const tzNeed = regionToStoreTz(postForText.region);
  if (tzNeed === null) {
    // неизвестный регион — не можем подобрать точки
    if (needTg) {
      out.push({
        json: {
          ...postForText,
          // NEW
          order_links,
          row_number: rowNumber,
          _now: nowLocal,
          _now_utc: nowUtcIso,
          _run_key: runKey,

          _tg_targets_empty: true,
          _tg_targets_reason: `unknown region=${postForText.region}`,
          _stores_debug: storesDebug,
        },
      });
    }
    continue;
  }

  // store_id цели
  let targetStoreIds = [];
  if (postForText.all_region) {
    for (const s of storesInput) {
      if (Number(s.time_zone) === tzNeed) {
        const id = Number(s.store_id);
        if (Number.isFinite(id)) targetStoreIds.push(id);
      }
    }
  } else {
    targetStoreIds = pickStoreIdsFromRaw(postForText._raw);
  }

  targetStoreIds = Array.from(new Set(targetStoreIds));

  if (targetStoreIds.length === 0) {
    if (needTg) {
      out.push({
        json: {
          ...postForText,
          // NEW
          order_links,
          row_number: rowNumber,
          _now: nowLocal,
          _now_utc: nowUtcIso,
          _run_key: runKey,

          _tg_targets_empty: true,
          _tg_targets_reason: postForText.all_region
            ? `no stores found for time_zone=${tzNeed} (stores_count=${storesInput.length}, tzs=${storesDebug.stores_time_zones.join(',')})`
            : 'no store columns selected in sheet row (no store_* = 1)',
          _stores_debug: storesDebug,
        },
      });
    }
    continue;
  }

  // ---- parse media ----
  const mediaRaw = (postForText.media_raw ?? postForText.media_url ?? postForText._raw?.media_raw ?? postForText._raw?.media_url ?? '').toString();
  const mediaArr = parseMediaLines(mediaRaw);

  // old_post parsing (only if present) — используется только для TG deep-link
  const oldParsed = parseOldPost(postForText.old_post ?? postForText._raw?.old_post);

  // date part for old_link in region tz
  const nowUtcObj = nowUtcIso ? new Date(nowUtcIso) : new Date();
  const datePart = formatDDMMYYYYInTz(nowUtcObj, tzName);

  // --- TG prep (как было) ---
  const tgBase = needTg ? buildTgTextAndMode(postForText) : null;
  const debugMode = needTg ? (Number(postForText.tg_debug) === 1) : false;

  // базовое решение по типу отправки (TG)
  let baseOpTg = 'message'; // message | photo | video | media_group
  let baseMediaTg = null;

  if (mediaArr.length === 0) {
    baseOpTg = 'message';
  } else if (mediaArr.length === 1) {
    baseOpTg = mediaArr[0].type === 'photo' ? 'photo' : 'video';
    baseMediaTg = mediaArr[0].media;
  } else {
    baseOpTg = 'media_group';
  }

  // --- MAX prep ---
  // MAX API: photo -> image (type=image)
  const mediaArrMax = mediaArr.map(m => ({
    type: m.type === 'photo' ? 'image' : 'video',
    media: m.media,
  }));

  let baseOpMax = 'message'; // message | image | video | media_group
  let baseMediaMax = null;

  if (mediaArrMax.length === 0) {
    baseOpMax = 'message';
  } else if (mediaArrMax.length === 1) {
    baseOpMax = mediaArrMax[0].type === 'image' ? 'image' : 'video';
    baseMediaMax = mediaArrMax[0].media;
  } else {
    baseOpMax = 'media_group';
  }

  const seenChat = new Set(); // TG dedupe by chat_id
  const seenMax = new Set();  // MAX dedupe by max_channel_id

  let producedTg = 0;
  let producedMax = 0;

  for (const storeId of targetStoreIds) {
    const s = storeMap.get(storeId);
    if (!s) continue;
    if (Number(s.time_zone) !== tzNeed) continue;

    const tgInvExptEmpty = !String(postForText.tg_inv_expt ?? '').trim();
    const tgInvite = tgInvExptEmpty ? cleanUrl(s.tg_invite_url_channel_friend) : null;
    const maxInvite = tgInvExptEmpty ? cleanUrl(s.max_invite_url_channel_friend) : null;

    // ---------------- TG ----------------
    if (needTg) {
      const chatId = debugMode ? TG_TEST_CHAT_ID : s.channel_chat_id;
      const chatKey = String(chatId);
      if (!chatId) {
        // если нет chat_id — пропускаем
      } else if (!seenChat.has(chatKey)) {
        seenChat.add(chatKey);

        let effectiveAuthType;

        if (debugMode) {
          // In debug mode we fully override post_auth_type based on TG_TEST_FORCE_AUTH_TYPE_1
          // true  => 1 (use order_link / inline buttons)
          // false => 0 (use old_post)
          effectiveAuthType = TG_TEST_FORCE_AUTH_TYPE_1 ? 1 : 0;
        } else {
          // In normal mode we use the value from the post row (if set) or fallback to the store row
          effectiveAuthType = Number(postForText.post_auth_type ?? s.post_auth_type);
        }

        const authType1 = effectiveAuthType === 1;

        // --- old link for this store (depends on storeId) ---
        // IMPORTANT: if post_auth_type = 1 -> ignore old_post completely
        const oldLink = (!authType1 && oldParsed)
          ? buildOldLink(oldParsed, storeId, datePart, tgBase.parse_mode)
          : null;

        // --- text final (Telegram) ---
        // post_auth_type = 1:
        //   - base text
        //   - then order_links block (from order_link)
        //   - then invite footer (if enabled)
        // else:
        //   - current behavior (oldLink + footer)
        let tgTextFinal = tgBase.text;

        if (authType1) {
  // post_auth_type = 1: DO NOT add order links into the text.
  // Links will be rendered as inline buttons (reply_markup) downstream.
} else {
  // post_auth_type != 1 (e.g. 0): add legacy link into the text.
  tgTextFinal = appendOldLinkToText(tgTextFinal, oldLink);
}

        if (tgInvExptEmpty) {
          const footer = buildInviteFooter(tgBase.parse_mode, tgInvite, maxInvite);
          tgTextFinal = appendFooter(tgTextFinal, footer);
        }

        // --- per-store media decision for albums: caption may be too long ---
        let tgOp = baseOpTg;
        let tgMedia = baseMediaTg;
        let tgMediaGroup = null;
        let needExtraTextMessage = false;

        if (baseOpTg === 'media_group') {
          // IMPORTANT:
          //  - Do NOT set caption inside sendMediaGroup items (inline buttons don't work under media groups).
          //  - Album media must be sent first; text is sent later as a separate message by downstream nodes.
          tgMediaGroup = mediaArr;

          if (tgTextFinal && tgTextFinal.trim()) {
            needExtraTextMessage = true;
          }
        }

        // 1) основной item
        out.push({
          json: {
            ...postForText,

            // NEW
            order_links,
            post_auth_type: effectiveAuthType,

            channel: 'tg',

            // служебные поля для апдейта Sheets
            row_number: rowNumber,
            _now: nowLocal,
            _now_utc: nowUtcIso,
            _run_key: runKey,

            // данные цели
            store_id: storeId,
            store_description: s.store_description ?? null,

            // routing for telegram
            tg_op: tgOp,
            tg_media: tgMedia,
            tg_media_group: tgMediaGroup,


            // helpers for sequential album -> text sending (used by HTTP Request -> If1 -> Send a text message1)
            tg_send_text_after_album: (tgOp === 'media_group' && needExtraTextMessage && tgTextFinal && tgTextFinal.trim()) ? true : false,
            tg_chat_id: chatId,
            tg_text: tgTextFinal,
            tg_parse_mode: tgBase.parse_mode,
            // old link debug
            _old_post_parsed: oldParsed,
            _old_post_date_ddmmyyyy: datePart,
            _old_post_link: oldLink,

            tg: {
              chat_id: chatId,
              text: tgTextFinal,
              parse_mode: tgBase.parse_mode,
              debug: debugMode,
            },

            _run_key_channel: runKey ? `${runKey}|tg|store:${storeId}` : null,
            _stores_debug: storesDebug,
          },
        });

        producedTg++;

        // 2) если альбом и текст длинный — отдельное сообщение текстом после альбома
        if (tgOp === 'media_group' && needExtraTextMessage) {
          // We intentionally do NOT create a second item here.
          // Otherwise it would go through the 'Send a text message' branch and might arrive BEFORE the album.
          // Text for the album is sent after sendMediaGroup by downstream nodes: HTTP Request -> If1 -> Send a text message1.
        }
      }
    }

    // ---------------- MAX ----------------
    if (needMax) {
      const maxChannelId = s.max_channel_id;
      const maxKey = String(maxChannelId ?? '');
      if (!maxChannelId) {
        // нет канала MAX у точки — пропускаем
      } else if (!seenMax.has(maxKey)) {
        seenMax.add(maxKey);

        let maxOp = baseOpMax;
        let maxMedia = baseMediaMax;
        let maxMediaGroup = null;

        if (baseOpMax === 'media_group') {
          maxMediaGroup = mediaArrMax;
        }

        // NEW: MAX text + invite footer (MARKDOWN links)
        let maxTextFinal = (postForText.text ?? '').toString().trim();

        function mdLink(label, url) {
          const u = String(url ?? '').trim();
          if (!u) return null;
          return `[${label}](${u})`;
        }

        if (tgInvExptEmpty) {
          const lines = [];

          const tgLink = mdLink('📢 Подпишись в Telegram', tgInvite);
          if (tgLink) lines.push(tgLink);

          const maxLink = mdLink('⚡ Подпишись в MAX', maxInvite);
          if (maxLink) lines.push(maxLink);

          if (lines.length) {
            const footer = lines.join('\n\n');
            maxTextFinal = maxTextFinal
              ? `${maxTextFinal}\n\n${footer}`
              : footer;
          }
        }

        out.push({
          json: {
            ...postForText,

            // NEW
            order_links,
            post_auth_type: Number(postForText.post_auth_type ?? s.post_auth_type ?? null),

            channel: 'max',

            row_number: rowNumber,
            _now: nowLocal,
            _now_utc: nowUtcIso,
            _run_key: runKey,

            store_id: storeId,
            store_description: s.store_description ?? null,

            max_op: maxOp,
            max_media: maxMedia,
            max_media_group: maxMediaGroup,

            max: {
              channel_id: maxChannelId,
              text: maxTextFinal,
            },

            _run_key_channel: runKey ? `${runKey}|max|store:${storeId}` : null,
            _stores_debug: storesDebug,
          },
        });

        producedMax++;
      }
    }
  }

  if (needTg && producedTg === 0) {
    out.push({
      json: {
        ...postForText,
        // NEW
        order_links,
        row_number: rowNumber,
        _now: nowLocal,
        _now_utc: nowUtcIso,
        _run_key: runKey,

        _tg_targets_empty: true,
        _tg_targets_reason: `stores selected but none matched mapping for time_zone=${tzNeed} (stores_count=${storesInput.length}, tzs=${storesDebug.stores_time_zones.join(',')})`,
        _stores_debug: storesDebug,
      },
    });
  }
}

return out;

/**
 * Collect TG results per post_id (after Merge Combine/Position)
 * Supports:
 *  - Telegram nodes (they often return { ok:true, result:... } or set p.error on continueRegularOutput)
 *  - HTTP Request node (sendMediaGroup) which may return:
 *      - { statusCode: 200, body: { ok:true, result:[...] } }  (when JSON)
 *      - { statusCode: 200, body: "..." }                      (when string)
 *      - errors in p.error / p.message / p.response / p.body
 *
 * Output: one item per post_id with aggregation + Sheets update fields
 */

const items = $input.all();

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function toNumOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function appendLog(existing, line) {
  const base = (existing ?? '').toString().trim();
  if (!base) return line;
  return base + '\n' + line;
}

function tryJsonParse(s) {
  try {
    return JSON.parse(s);
  } catch (e) {
    return null;
  }
}

// --- Detect ok for both Telegram node and HTTP Request node ---
function detectOk(p) {
  if (!p) return false;

  // Telegram node common
  if (p.ok === true || p.success === true) return true;

  // HTTP Request node common shapes
  // 1) response object
  if (p.response && (p.response.ok === true || p.response.success === true)) return true;

  // 2) body may be object or stringified json
  const body = p.body ?? p.response?.body ?? null;
  if (body && typeof body === 'object') {
    if (body.ok === true) return true;
    // sometimes nested
    if (body.data?.ok === true) return true;
  }
  if (typeof body === 'string') {
    const j = tryJsonParse(body);
    if (j && j.ok === true) return true;
  }

  // 3) n8n httpRequest often exposes statusCode
  const sc = p.statusCode ?? p.status ?? p.response?.statusCode ?? null;
  if (typeof sc === 'number' && sc >= 200 && sc < 300) {
    // If Telegram returns non-ok with 200, we'd have body.ok=false.
    // But if we can't see body, treat 2xx as ok to avoid false FAIL logs.
    return true;
  }

  return false;
}

function extractErrorText(p) {
  if (!p) return 'unknown error';

  // Telegram node error object
  if (typeof p.error === 'string') return p.error;
  if (p.error?.message) return safeStr(p.error.message);

  // httpRequest node sometimes exposes errorMessage / message
  if (p.errorMessage) return safeStr(p.errorMessage);
  if (p.message) return safeStr(p.message);
  if (p.description) return safeStr(p.description);
  if (p.cause) return safeStr(p.cause);

  // response/body shapes
  const body = p.body ?? p.response?.body ?? p.responseBody ?? null;

  if (body && typeof body === 'object') {
    if (body.description) return safeStr(body.description);
    if (body.error) return safeStr(body.error);
    if (body.message) return safeStr(body.message);
    if (body.ok === false && body.description) return safeStr(body.description);
    try {
      return JSON.stringify(body);
    } catch (e) {
      return 'unstringifiable body';
    }
  }

  if (typeof body === 'string') {
    const j = tryJsonParse(body);
    if (j) {
      if (j.description) return safeStr(j.description);
      if (j.error) return safeStr(j.error);
      if (j.message) return safeStr(j.message);
      if (j.ok === false && j.description) return safeStr(j.description);
      try {
        return JSON.stringify(j);
      } catch (e) {}
    }
    // raw string body
    const s = body.trim();
    if (s) return s.slice(0, 500);
  }

  // fallback stringify whole p.error if exists
  if (p.error) {
    try {
      return JSON.stringify(p.error);
    } catch (e) {
      return 'unstringifiable error';
    }
  }

  return 'unknown error';
}

// group per post_id
const byPost = new Map();

for (const item of items) {
  const p = item.json || {};

  const postId = p.post_id ?? p.id ?? null;
  if (!postId) continue;

  if (!byPost.has(postId)) {
    byPost.set(postId, {
      post_id: postId,
      row_number: toNumOrNull(p.row_number),

      last_run_key: p._run_key ?? null,
      now_utc: p._now_utc ?? new Date().toISOString(),
      now_local: p._now ?? null,

      plan_run_at: p._plan_run_at ?? null,
      prev_error: p.error_prev ?? null,

      total: 0,
      ok: 0,
      fail: 0,
      fails: [],
    });
  }

  const agg = byPost.get(postId);

  if (!agg.plan_run_at && p._plan_run_at) agg.plan_run_at = p._plan_run_at;

  agg.total += 1;

  const ok = detectOk(p);

  const storeId = p.store_id ?? null;
  const chatId = p.tg_chat_id ?? p.chat_id ?? null;

  if (ok) {
    agg.ok += 1;
  } else {
    agg.fail += 1;
    const desc = extractErrorText(p);
    agg.fails.push({
      store_id: storeId,
      chat_id: chatId,
      desc: safeStr(desc),
    });
  }
}

const out = [];

for (const agg of byPost.values()) {
  // success only if at least one ok and no fails
  const allOk = agg.fail === 0 && agg.ok > 0;

  let newError = agg.prev_error;

  if (allOk) {
    newError = appendLog(
      newError,
      `[OK TG] ${agg.now_utc} key=${safeStr(agg.last_run_key)} sent=${agg.ok}/${agg.total}`
    );
  } else {
    const failLines = agg.fails
      .slice(0, 20)
      .map(f => `store=${safeStr(f.store_id)} chat=${safeStr(f.chat_id)} err=${safeStr(f.desc)}`)
      .join(' | ');

    newError = appendLog(
      newError,
      `[FAIL TG] ${agg.now_utc} key=${safeStr(agg.last_run_key)} ok=${agg.ok}/${agg.total} fails=${agg.fail}` +
        (failLines ? ` :: ${failLines}` : '')
    );
  }

  out.push({
    json: {
      post_id: agg.post_id,
      row_number: agg.row_number,

      _all_ok: allOk,
      _sent_ok: agg.ok,
      _sent_fail: agg.fail,
      _sent_total: agg.total,

      update_last_run_at_utc: allOk ? agg.now_utc : null,
      update_last_run_at: allOk ? agg.now_local : null,
      update_last_run_key: allOk ? agg.last_run_key : null,

      // write plan_run_at only on success
      update_plan_run_at: allOk ? (agg.plan_run_at ?? null) : null,

      update_error: newError,
    },
  });
}

return out;

function regionToTz(region) {
  if (region === 54) return 'Asia/Novosibirsk';
  if (region === 82) return 'Europe/Simferopol';
  return 'Europe/Moscow';
}

function cleanLine(s) {
  return String(s ?? '')
    .replace(/[\uFEFF\u200B\u200C\u200D\u2060\u00AD]/g, '')
    .trim();
}

function formatLocalHuman(utcDate, tz) {
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    hour12: false,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });

  const parts = dtf.formatToParts(utcDate);
  const map = {};
  for (const p of parts) if (p.type !== 'literal') map[p.type] = p.value;

  // пробел вместо T — людям проще
  return `${map.year}-${map.month}-${map.day} ${map.hour}:${map.minute}:${map.second} (${tz})`;
}

// FIX: принимаем 1-2 цифры для часа (и для minutes/seconds тоже позволим 1-2 на всякий случай)
function parseLocal(value) {
  const s = cleanLine(value);
  if (!s) return null;

  // 0) YYYYMMDDTHHMMSS или YYYYMMDDTHHMM
  let m = s.match(/^(\d{4})(\d{2})(\d{2})T(\d{1,2})(\d{1,2})(\d{1,2})?$/);
  if (m) {
    const [_, Y, M, D, h, min, sec] = m;
    const hh = Number(h);
    const mm = Number(min);
    const ss = sec ? Number(sec) : 0;
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || !Number.isFinite(ss)) return null;
    if (hh < 0 || hh > 23 || mm < 0 || mm > 59 || ss < 0 || ss > 59) return null;
    return { Y: +Y, M: +M, D: +D, h: hh, min: mm, s: ss };
  }

  // 1) YYYY-MM-DD HH:mm(:ss)
  m = s.match(/^(\d{4})-(\d{2})-(\d{2})[ T](\d{1,2}):(\d{1,2})(?::(\d{1,2}))?$/);
  if (m) {
    const [_, Y, M, D, h, min, sec] = m;
    const hh = Number(h);
    const mm = Number(min);
    const ss = sec ? Number(sec) : 0;
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || !Number.isFinite(ss)) return null;
    if (hh < 0 || hh > 23 || mm < 0 || mm > 59 || ss < 0 || ss > 59) return null;
    return { Y: +Y, M: +M, D: +D, h: hh, min: mm, s: ss };
  }

  // 2) DD.MM.YYYY HH:mm(:ss)
  m = s.match(/^(\d{2})\.(\d{2})\.(\d{4})[ T](\d{1,2}):(\d{1,2})(?::(\d{1,2}))?$/);
  if (m) {
    const [_, D, M, Y, h, min, sec] = m;
    const hh = Number(h);
    const mm = Number(min);
    const ss = sec ? Number(sec) : 0;
    if (!Number.isFinite(hh) || !Number.isFinite(mm) || !Number.isFinite(ss)) return null;
    if (hh < 0 || hh > 23 || mm < 0 || mm > 59 || ss < 0 || ss > 59) return null;
    return { Y: +Y, M: +M, D: +D, h: hh, min: mm, s: ss };
  }

  return null;
}

function isIsoLike(value) {
  const s = cleanLine(value);
  return /T/.test(s) || /Z$/.test(s) || /[+-]\d{2}:\d{2}$/.test(s);
}

function tzOffsetMinutesAt(utcDate, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', {
    timeZone,
    hour12: false,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });

  const parts = dtf.formatToParts(utcDate);
  const map = {};
  for (const p of parts) if (p.type !== 'literal') map[p.type] = p.value;

  const asIfUtc = Date.UTC(
    Number(map.year),
    Number(map.month) - 1,
    Number(map.day),
    Number(map.hour),
    Number(map.minute),
    Number(map.second),
  );

  const offsetMs = asIfUtc - utcDate.getTime();
  return Math.round(offsetMs / 60000);
}

function dateFromLocalInTz(local, timeZone) {
  const approxUtc = new Date(Date.UTC(local.Y, local.M - 1, local.D, local.h, local.min, local.s, 0));

  const offsetMin1 = tzOffsetMinutesAt(approxUtc, timeZone);

  let utcMs = approxUtc.getTime() - offsetMin1 * 60000;
  let utcDate = new Date(utcMs);

  const offsetMin2 = tzOffsetMinutesAt(utcDate, timeZone);
  if (offsetMin2 !== offsetMin1) {
    utcMs = approxUtc.getTime() - offsetMin2 * 60000;
    utcDate = new Date(utcMs);
  }

  return utcDate;
}

function parseDateTimeByTz(value, timeZone) {
  const v = cleanLine(value);
  if (!v) return null;

  // ISO со смещением/UTC — парсим напрямую
  if (isIsoLike(v)) {
    const iso = Date.parse(v);
    return Number.isNaN(iso) ? null : new Date(iso);
  }

  // Иначе — локальное время TZ
  const local = parseLocal(v);
  if (!local) return null;

  return dateFromLocalInTz(local, timeZone);
}

function parseDateTimeByRegion(value, region) {
  const tz = regionToTz(region);
  return parseDateTimeByTz(value, tz);
}

// ---------------- schedule mini DSL ----------------

/**
 * IMPORTANT FIX:
 * Раньше мы "расщепляли" весь schedule по ';', из-за чего RRULE разваливался,
 * и BYDAY часто терялся (становился null).
 *
 * Теперь:
 * - НИКОГДА не делим весь текст по ';'
 * - Ищем строки DTSTART / RRULE / TZ / UNTIL по всему тексту
 * - ';' используем только внутри rruleRaw (rruleRaw.split(';'))
 */
function parseSchedule(scheduleText) {
  const raw0 = (scheduleText ?? '').toString();
  const raw = raw0.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  if (!cleanLine(raw)) return { ok: false, error: 'schedule empty' };

  const findVal = (key) => {
    const re = new RegExp(`(?:^|\\n)\\s*${key}(?:;[^:=]*)?\\s*[:=]\\s*(.+?)\\s*(?=\\n|$)`, 'i');
    const m = raw.match(re);
    return m ? cleanLine(m[1]) : null;
  };

  const tz = findVal('TZ');
  const dtstartRaw = findVal('DTSTART');
  const rruleRaw = findVal('RRULE');
  const untilRaw = findVal('UNTIL');

  if (!dtstartRaw) return { ok: false, error: 'DTSTART missing' };
  if (!rruleRaw) return { ok: false, error: 'RRULE missing' };

  const props = {};
  for (const part0 of rruleRaw.split(';')) {
    const part = cleanLine(part0);
    if (!part) continue;

    const eq = part.indexOf('=');
    if (eq <= 0) continue;

    const k = cleanLine(part.slice(0, eq)).toUpperCase();
    const v = cleanLine(part.slice(eq + 1));
    if (!k || v == null) continue;

    props[k] = v;
  }

  const freq = (props.FREQ || '').toUpperCase();
  if (!['DAILY', 'WEEKLY', 'MONTHLY'].includes(freq)) {
    return { ok: false, error: `Unsupported FREQ=${props.FREQ || ''}` };
  }

  const interval = props.INTERVAL ? Math.max(1, Number(props.INTERVAL)) : 1;
  const count = props.COUNT ? Math.max(1, Number(props.COUNT)) : null;
  const untilStr = props.UNTIL || untilRaw || null;

  const byday = props.BYDAY
    ? props.BYDAY.split(',').map(s => cleanLine(s).toUpperCase()).filter(Boolean)
    : null;

  const byhour = props.BYHOUR != null
    ? props.BYHOUR.split(',').map(x => Number(cleanLine(x)))
    : null;

  const byminute = props.BYMINUTE != null
    ? props.BYMINUTE.split(',').map(x => Number(cleanLine(x)))
    : null;

  return { ok: true, tz, dtstartRaw, freq, interval, count, untilStr, byday, byhour, byminute, raw: { rruleRaw, scheduleRaw: raw } };
}

function formatPartsYMDInTz(utcDate, tz) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(utcDate);

  const map = {};
  for (const p of parts) if (p.type !== 'literal') map[p.type] = p.value;

  return { y: Number(map.year), m: Number(map.month), d: Number(map.day) };
}

function localYmdHmsToUtc(y, m, d, hh, mm, ss, tz) {
  return dateFromLocalInTz({ Y: y, M: m, D: d, h: hh, min: mm, s: ss }, tz);
}

function addDaysUtc(date, days) {
  return new Date(date.getTime() + days * 86400000);
}

function addWeeksUtc(date, weeks) {
  return addDaysUtc(date, weeks * 7);
}

function addMonthsUtc(date, months) {
  const y = date.getUTCFullYear();
  const m = date.getUTCMonth();
  const d = date.getUTCDate();
  const hh = date.getUTCHours();
  const mm = date.getUTCMinutes();
  const ss = date.getUTCSeconds();

  const targetMonthIndex = m + months;
  const targetY = y + Math.floor(targetMonthIndex / 12);
  const targetM = ((targetMonthIndex % 12) + 12) % 12;

  const lastDay = new Date(Date.UTC(targetY, targetM + 1, 0)).getUTCDate();
  const clampedD = Math.min(d, lastDay);

  return new Date(Date.UTC(targetY, targetM, clampedD, hh, mm, ss));
}

function makeRunKeyLocal(postId, tz, occurrenceUtc) {
  const id = (postId ?? 'unknown').toString();
  const local = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    hour12: false,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  }).format(occurrenceUtc).replace(', ', ' ');
  return `post:${id}|${tz}|${local}`;
}

/**
 * Stable weekday for a LOCAL date (y,m,d) in timezone tz.
 * We convert local noon to UTC and then format weekday in tz.
 * Noon avoids boundary issues around midnight and DST.
 * Returns two-letter codes: MO,TU,WE,TH,FR,SA,SU.
 */
function weekdayFromLocalYmd(y, m, d, tz) {
  const probeUtc = localYmdHmsToUtc(y, m, d, 12, 0, 0, tz);
  const w = new Intl.DateTimeFormat('en-US', { timeZone: tz, weekday: 'short' })
    .format(probeUtc)
    .slice(0, 2)
    .toUpperCase();
  return w;
}

function findLastOccurrenceUtc({ tz, dtstartUtc, dtstartLocalParts, rule, untilUtc, nowUtc }) {
  let windowStartUtc;
  if (rule.freq === 'DAILY') windowStartUtc = new Date(nowUtc.getTime() - 40 * 86400000);
  else if (rule.freq === 'WEEKLY') windowStartUtc = new Date(nowUtc.getTime() - 26 * 7 * 86400000);
  else windowStartUtc = new Date(nowUtc.getTime() - 24 * 31 * 86400000);

  if (windowStartUtc < dtstartUtc) windowStartUtc = dtstartUtc;
  const windowEndUtc = nowUtc;

  const defaultH = dtstartLocalParts.h;
  const defaultM = dtstartLocalParts.min;
  const defaultS = dtstartLocalParts.s;

  const hours = rule.byhour && rule.byhour.length ? rule.byhour : [defaultH];
  const minutes = rule.byminute && rule.byminute.length ? rule.byminute : [defaultM];

  let last = null;
  let produced = 0;
  const maxProduced = 5000;

  if (rule.freq === 'DAILY') {
    let cursor = new Date(Date.UTC(
      windowStartUtc.getUTCFullYear(),
      windowStartUtc.getUTCMonth(),
      windowStartUtc.getUTCDate(),
      0, 0, 0
    ));

    const dt0 = new Date(Date.UTC(
      dtstartUtc.getUTCFullYear(),
      dtstartUtc.getUTCMonth(),
      dtstartUtc.getUTCDate(),
      0, 0, 0
    ));

    let diffDays = Math.floor((cursor.getTime() - dt0.getTime()) / 86400000);
    if (diffDays < 0) diffDays = 0;
    const mod = diffDays % rule.interval;
    if (mod !== 0) cursor = addDaysUtc(cursor, rule.interval - mod);

    while (cursor <= windowEndUtc && produced < maxProduced) {
      const ymd = formatPartsYMDInTz(cursor, tz);

      if (rule.byday && rule.byday.length) {
        const localWday = weekdayFromLocalYmd(ymd.y, ymd.m, ymd.d, tz);
        if (!rule.byday.includes(localWday)) {
          cursor = addDaysUtc(cursor, rule.interval);
          continue;
        }
      }

      for (const hh of hours) {
        for (const mm of minutes) {
          const occUtc = localYmdHmsToUtc(ymd.y, ymd.m, ymd.d, hh, mm, defaultS, tz);
          if (occUtc < dtstartUtc) continue;
          if (untilUtc && occUtc > untilUtc) continue;
          if (occUtc < windowStartUtc || occUtc > windowEndUtc) continue;

          produced++;
          if (rule.count && produced > rule.count) return last;

          if (!last || occUtc > last) last = occUtc;
          if (produced >= maxProduced) break;
        }
        if (produced >= maxProduced) break;
      }

      cursor = addDaysUtc(cursor, rule.interval);
    }
  }

  if (rule.freq === 'WEEKLY') {
    const dtLocalWday = weekdayFromLocalYmd(dtstartLocalParts.Y, dtstartLocalParts.M, dtstartLocalParts.D, tz);
    const days = (rule.byday && rule.byday.length) ? rule.byday : [dtLocalWday];

    let cursorWeekStart = new Date(Date.UTC(
      windowStartUtc.getUTCFullYear(),
      windowStartUtc.getUTCMonth(),
      windowStartUtc.getUTCDate(),
      0, 0, 0
    ));

    const dt0 = new Date(Date.UTC(
      dtstartUtc.getUTCFullYear(),
      dtstartUtc.getUTCMonth(),
      dtstartUtc.getUTCDate(),
      0, 0, 0
    ));

    let diffDays = Math.floor((cursorWeekStart.getTime() - dt0.getTime()) / 86400000);
    if (diffDays < 0) diffDays = 0;
    const diffWeeks = Math.floor(diffDays / 7);
    const mod = diffWeeks % rule.interval;
    if (mod !== 0) cursorWeekStart = addWeeksUtc(cursorWeekStart, rule.interval - mod);

    while (cursorWeekStart <= windowEndUtc && produced < maxProduced) {
      for (let i = 0; i < 7; i++) {
        const dayUtc = addDaysUtc(cursorWeekStart, i);
        const ymd = formatPartsYMDInTz(dayUtc, tz);
        const localWday = weekdayFromLocalYmd(ymd.y, ymd.m, ymd.d, tz);

        if (!days.includes(localWday)) continue;

        for (const hh of hours) {
          for (const mm of minutes) {
            const occUtc = localYmdHmsToUtc(ymd.y, ymd.m, ymd.d, hh, mm, defaultS, tz);
            if (occUtc < dtstartUtc) continue;
            if (untilUtc && occUtc > untilUtc) continue;
            if (occUtc < windowStartUtc || occUtc > windowEndUtc) continue;

            produced++;
            if (rule.count && produced > rule.count) return last;

            if (!last || occUtc > last) last = occUtc;
            if (produced >= maxProduced) break;
          }
          if (produced >= maxProduced) break;
        }
      }

      cursorWeekStart = addWeeksUtc(cursorWeekStart, rule.interval);
    }
  }

  if (rule.freq === 'MONTHLY') {
    let cursor = dtstartUtc;
    let iterations = 0;
    const maxIter = 300;

    while (cursor < windowStartUtc && iterations < maxIter) {
      cursor = addMonthsUtc(cursor, rule.interval);
      iterations++;
    }

    while (cursor <= windowEndUtc && iterations < maxIter && produced < maxProduced) {
      const ymd = formatPartsYMDInTz(cursor, tz);

      for (const hh of hours) {
        for (const mm of minutes) {
          const occUtc = localYmdHmsToUtc(ymd.y, ymd.m, ymd.d, hh, mm, defaultS, tz);
          if (occUtc < dtstartUtc) continue;
          if (untilUtc && occUtc > untilUtc) continue;
          if (occUtc < windowStartUtc || occUtc > windowEndUtc) continue;

          produced++;
          if (rule.count && produced > rule.count) return last;

          if (!last || occUtc > last) last = occUtc;
          if (produced >= maxProduced) break;
        }
        if (produced >= maxProduced) break;
      }

      cursor = addMonthsUtc(cursor, rule.interval);
      iterations++;
    }
  }

  return last;
}

// NEW: find next occurrence strictly after nowUtc
function findNextOccurrenceUtc({ tz, dtstartUtc, dtstartLocalParts, rule, untilUtc, nowUtc }) {
