// ---------------- main ----------------

const items = $input.all();
const nowUtc = new Date();

return items.map(item => {
  const p = item.json;

  const tzRegion = regionToTz(p.region);

  let due = false;
  let reason = null;

  // наружные поля
  const nowLocal = formatLocalHuman(nowUtc, tzRegion);

  let publishUtc = null;
  let publishLocal = null;

  let occurrenceUtc = null;
  let occurrenceLocal = null;

  let runKey = null;
  let scheduleParsed = null;

  // NEW plan
  let planRunUtc = null;
  let planRunLocal = null;

  if (p.post_type === 2) {
    publishUtc = parseDateTimeByRegion(p.publish_at, p.region);
    publishLocal = publishUtc ? formatLocalHuman(publishUtc, tzRegion) : null;

    if (!publishUtc) {
      reason = 'one-time post without valid publish_at';
    } else {
      // для разового поста occurrence = publish_at
      occurrenceUtc = publishUtc;
      occurrenceLocal = formatLocalHuman(occurrenceUtc, tzRegion);

      // формируем ключ заранее (антидубль как у регулярных)
      runKey = makeRunKeyLocal(p.id, tzRegion, occurrenceUtc);

      const alreadyKey = (p.last_run_key ?? '').toString().trim();
      if (alreadyKey === runKey) {
        due = false;
        reason = 'one-time: already executed (last_run_key match)';
      } else {
        // запасной стопор по last_run_at_utc (если ключ почему-то не писался)
        const lastRunAtUtc = p.last_run_at_utc ? new Date(p.last_run_at_utc) : null;
        if (lastRunAtUtc && !isNaN(lastRunAtUtc.getTime())) {
          if (lastRunAtUtc.getTime() >= occurrenceUtc.getTime() - 30 * 1000) {
            due = false;
            reason = 'one-time: already executed (last_run_at_utc >= publish_at)';
          } else if (publishUtc <= nowUtc) {
            due = true;
            reason = 'due now (publish_at <= now) in region tz';
          } else {
            due = false;
            reason = 'not yet (publish_at in future) in region tz';
          }
        } else {
          if (publishUtc <= nowUtc) {
            due = true;
            reason = 'due now (publish_at <= now) in region tz';
          } else {
            due = false;
            reason = 'not yet (publish_at in future) in region tz';
          }
        }
      }
    }
  } else if (p.post_type === 1) {
    if (!p.schedule) {
      reason = 'regular post without schedule';
    } else {
      const parsed = parseSchedule(p.schedule);
      if (!parsed.ok) {
        reason = `schedule parse error: ${parsed.error}`;
      } else {
        const tz = parsed.tz || tzRegion;

        const dtstartLocal = parseLocal(parsed.dtstartRaw);
        if (!dtstartLocal) {
          reason = 'DTSTART parse error';
        } else {
          const dtstartUtc = dateFromLocalInTz(dtstartLocal, tz);

          let untilUtc = null;
          if (parsed.untilStr) {
            const u = parseDateTimeByTz(parsed.untilStr, tz);
            if (!u) reason = 'UNTIL parse error';
            else untilUtc = u;
          }

          if (!reason) {
            const rule = {
              freq: parsed.freq,
              interval: parsed.interval,
              count: parsed.count,
              byday: parsed.byday,
              byhour: parsed.byhour,
              byminute: parsed.byminute,
            };

            scheduleParsed = {
              tz,
              dtstart_local: parsed.dtstartRaw,
              dtstart_utc: dtstartUtc.toISOString(),
              rule,
              until_utc: untilUtc ? untilUtc.toISOString() : null,
              raw: parsed.raw, // чтобы видеть rruleRaw/scheduleRaw в дебаге
            };

            const lastOcc = findLastOccurrenceUtc({
              tz,
              dtstartUtc,
              dtstartLocalParts: dtstartLocal,
              rule,
              untilUtc,
              nowUtc,
            });

            const nextOcc = findNextOccurrenceUtc({
              tz,
              dtstartUtc,
              dtstartLocalParts: dtstartLocal,
              rule,
              untilUtc,
              nowUtc,
            });

            if (nextOcc) {
              planRunUtc = nextOcc;
              planRunLocal = formatLocalHuman(nextOcc, tz);
            } else {
              planRunUtc = null;
              planRunLocal = null;
            }

            if (!lastOcc) {
              // FIX: корректная причина, когда DTSTART ещё не наступил (в будущем)
              if (dtstartUtc > nowUtc) {
                due = false;
                reason = 'recurring: not yet started (DTSTART in future)';
              } else {
                // если DTSTART уже был в прошлом, но в lookback ничего не нашли
                due = false;
                reason = 'recurring: no occurrence found in lookback window';
              }
            } else {
              occurrenceUtc = lastOcc;
              occurrenceLocal = formatLocalHuman(occurrenceUtc, tz);
              runKey = makeRunKeyLocal(p.id, tz, occurrenceUtc);

              const alreadyKey = (p.last_run_key ?? '').toString().trim();
              if (alreadyKey === runKey) {
                due = false;
                reason = 'recurring: already executed (last_run_key match)';
              } else {
                // secondary: last_run_at_utc (надежно парсится)
                const lastRunAtUtc = p.last_run_at_utc ? new Date(p.last_run_at_utc) : null;
                if (lastRunAtUtc && !isNaN(lastRunAtUtc.getTime())) {
                  if (lastRunAtUtc.getTime() >= occurrenceUtc.getTime() - 30 * 1000) {
                    due = false;
                    reason = 'recurring: already executed (last_run_at_utc >= occurrence)';
                  } else {
                    due = true;
                    reason = 'recurring: occurrence <= now and not executed';
                  }
                } else {
                  due = true;
                  reason = 'recurring: occurrence <= now and not executed';
                }
              }
            }
          }
        }
      }
    }
  } else {
    reason = 'unknown post_type';
  }

  return {
    json: {
      ...p,
      _due: due,
      _due_reason: reason,

      // локальное отображение
      _now: nowLocal,
      _publish_at_parsed: publishLocal,
      _occurrence_local: occurrenceLocal,

      // UTC техничка (для записи)
      _now_utc: nowUtc.toISOString(),
      _occurrence_utc: occurrenceUtc ? occurrenceUtc.toISOString() : null,

      _run_key: runKey,
      _schedule_parsed: scheduleParsed,

      // NEW: next planned run (for regular posts)
      _plan_run_at: planRunLocal,
      _plan_run_at_utc: planRunUtc ? planRunUtc.toISOString() : null,
    },
  };
});

/**
 * Collect VK results per post_id (after Merge Combine/Position)
 *
 * Supports VK API responses from HTTP Request node (wall.post), which typically return:
 *  - Success: { response: { post_id: 123, ... } }
 *  - Error:   { error: { error_code: 214, error_msg: "...", error_text: "...", request_params: [...] } }
 *
 * But n8n can wrap HTTP responses as:
 *  - { statusCode: 200, body: { response:{...} } }  (when Response Format = JSON)
 *  - { statusCode: 200, body: "..." }              (string)
 *  - errors in p.error / p.message / p.response / p.body
 *
 * Output: one item per post_id with aggregation + Sheets update-like fields
 * (Note: do NOT write last_run_* here if you plan to require TG+VK together;
 *        you can still output vk_ok/vk_fail counts and update_error here.)
 */

const items = $input.all();

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function toNumOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function appendLog(existing, line) {
  const base = (existing ?? '').toString().trim();
  if (!base) return line;
  return base + '\n' + line;
}

function tryJsonParse(s) {
  try {
    return JSON.parse(s);
  } catch (e) {
    return null;
  }
}

function unwrapBody(p) {
  // n8n HTTP Request may expose body at top-level or nested
  const body = p?.body ?? p?.response?.body ?? p?.responseBody ?? null;

  if (body && typeof body === 'object') return body;

  if (typeof body === 'string') {
    const j = tryJsonParse(body);
    if (j && typeof j === 'object') return j;
  }

  // Sometimes response itself is the VK json
  if (p && typeof p === 'object') {
    if (p.response && typeof p.response === 'object') return p.response;
    // if p has response/error at top-level, return p itself
    if (p.response || p.error) return p;
  }

  return null;
}

function detectOk(p) {
  if (!p) return false;

  // Direct VK shape
  if (p.response && typeof p.response === 'object' && (p.response.post_id || p.response.post_id === 0)) {
    return true;
  }

  const b = unwrapBody(p);
  if (b) {
    if (b.response && typeof b.response === 'object' && (b.response.post_id || b.response.post_id === 0)) {
      return true;
    }
    // VK sometimes returns "response": 1 for some methods, but wall.post should return object
    if (typeof b.response === 'number' && b.response > 0) return true;
  }

  // Fallback: if statusCode is 2xx but VK error not visible, treat as ok (avoid false FAIL)
  const sc = p.statusCode ?? p.status ?? p.response?.statusCode ?? null;
  if (typeof sc === 'number' && sc >= 200 && sc < 300) {
    const bb = b;
    if (bb && bb.error) return false;
    return true;
  }

  return false;
}

function extractErrorText(p) {
  if (!p) return 'unknown error';

  // n8n error object
  if (typeof p.error === 'string') return p.error;
  if (p.error?.message) return safeStr(p.error.message);
  if (p.errorMessage) return safeStr(p.errorMessage);
  if (p.message) return safeStr(p.message);
  if (p.description) return safeStr(p.description);
  if (p.cause) return safeStr(p.cause);

  // VK error shape
  const b = unwrapBody(p);
  const errObj = b?.error ?? p?.error ?? null;

  if (errObj && typeof errObj === 'object') {
    const code = errObj.error_code ?? errObj.code ?? null;
    const msg = errObj.error_msg ?? errObj.message ?? errObj.error_text ?? null;
    if (code !== null || msg) {
      return `vk_error${code !== null ? `#${safeStr(code)}` : ''}: ${safeStr(msg || 'unknown')}`.trim();
    }
    try {
      return JSON.stringify(errObj);
    } catch (e) {
      return 'unstringifiable vk error';
    }
  }

  // Raw body as string
  const rawBody = p.body ?? p.response?.body ?? p.responseBody ?? null;
  if (typeof rawBody === 'string') {
    const s = rawBody.trim();
    if (s) return s.slice(0, 500);
  }

  // Last resort
  try {
    return JSON.stringify(p).slice(0, 500);
  } catch (e) {
    return 'unknown error';
  }
}

function extractVkPostId(p) {
  const b = unwrapBody(p);
  const direct = p?.response?.post_id ?? null;
  if (direct !== null && direct !== undefined) return direct;

  const pid = b?.response?.post_id ?? null;
  if (pid !== null && pid !== undefined) return pid;

  return null;
}

// group per post_id
const byPost = new Map();

for (const item of items) {
  const p = item.json || {};

  const postId = p.post_id ?? p.id ?? null;
  if (!postId) continue;

  if (!byPost.has(postId)) {
    byPost.set(postId, {
      post_id: postId,
      row_number: toNumOrNull(p.row_number),

      last_run_key: p._run_key ?? null,
      now_utc: p._now_utc ?? new Date().toISOString(),
      now_local: p._now ?? null,

      plan_run_at: p._plan_run_at ?? null,
      prev_error: p.error_prev ?? null,

      total: 0,
      ok: 0,
      fail: 0,
      fails: [],
      vk_post_ids: [],
    });
  }

  const agg = byPost.get(postId);

  if (!agg.plan_run_at && p._plan_run_at) agg.plan_run_at = p._plan_run_at;

  agg.total += 1;

  const ok = detectOk(p);

  if (ok) {
    agg.ok += 1;
    const vkPid = extractVkPostId(p);
    if (vkPid !== null && vkPid !== undefined) agg.vk_post_ids.push(vkPid);
  } else {
    agg.fail += 1;
    const desc = extractErrorText(p);
    agg.fails.push({ desc: safeStr(desc) });
  }
}

const out = [];

for (const agg of byPost.values()) {
  // success only if at least one ok and no fails
  const allOk = agg.fail === 0 && agg.ok > 0;

  let newError = agg.prev_error;

  if (allOk) {
    const vkInfo = agg.vk_post_ids.length ? ` vk_post_id=${safeStr(agg.vk_post_ids[0])}` : '';
    newError = appendLog(
      newError,
      `[OK VK] ${agg.now_utc} key=${safeStr(agg.last_run_key)} sent=${agg.ok}/${agg.total}${vkInfo}`
    );
  } else {
    const failLines = agg.fails
      .slice(0, 20)
      .map(f => `err=${safeStr(f.desc)}`)
      .join(' | ');

    newError = appendLog(
      newError,
      `[FAIL VK] ${agg.now_utc} key=${safeStr(agg.last_run_key)} ok=${agg.ok}/${agg.total} fails=${agg.fail}` +
        (failLines ? ` :: ${failLines}` : '')
    );
  }

  out.push({
    json: {
      post_id: agg.post_id,
      row_number: agg.row_number,

      _vk_all_ok: allOk,
      _vk_sent_ok: agg.ok,
      _vk_sent_fail: agg.fail,
      _vk_sent_total: agg.total,

      // Keep these in case you want final aggregator to decide.
      update_last_run_at_utc: allOk ? agg.now_utc : null,
      update_last_run_at: allOk ? agg.now_local : null,
      update_last_run_key: allOk ? agg.last_run_key : null,

      // write plan_run_at only on success
      update_plan_run_at: allOk ? (agg.plan_run_at ?? null) : null,

      update_error: newError,

      // optional: useful for debugging
      vk_post_ids: agg.vk_post_ids,
    },
  });
}

return out;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

/**
 * Final Collect (TG + VK + MAX) per post_id
 *
 * Input: mixed items from:
 *  - Collect TG results
 *  - Collect VK results
 *  - Collect MAX results
 *
 * Goal:
 *  - decide final _all_ok ONLY when all enabled channels succeeded
 *  - build one aggregated update_error log per post
 *  - output ONE item per post_id with fields for Google Sheets update:
 *      - update_last_run_at_utc / update_last_run_at / update_last_run_key / update_plan_run_at (ALWAYS, even if _all_ok=false)
 *      - update_error (always)
 */

const items = $input.all();

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function toBoolOrNull(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  const s = String(v).trim().toLowerCase();
  if (s === '') return null;
  if (s === '1' || s === 'true' || s === 'yes' || s === 'y') return true;
  if (s === '0' || s === 'false' || s === 'no' || s === 'n') return false;
  return null;
}

function toNumOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function appendLog(existing, line) {
  const base = (existing ?? '').toString().trim();
  if (!base) return line;
  return base + '\n' + line;
}

function isTgCollectorItem(p) {
  // TG collector outputs: _sent_ok/_sent_fail/_sent_total and _all_ok
  return p && (p._sent_total !== undefined || p._sent_ok !== undefined || p._sent_fail !== undefined);
}

function isVkCollectorItem(p) {
  // VK collector outputs: _vk_sent_total/_vk_sent_ok/_vk_sent_fail and _vk_all_ok
  return p && (p._vk_sent_total !== undefined || p._vk_sent_ok !== undefined || p._vk_sent_fail !== undefined);
}

function isMaxCollectorItem(p) {
  // MAX collector outputs: _max_sent_total/_max_sent_ok/_max_sent_fail and _max_all_ok
  return p && (p._max_sent_total !== undefined || p._max_sent_ok !== undefined || p._max_sent_fail !== undefined);
}

function pickFirstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

// Group per post_id
const byPost = new Map();

for (const item of items) {
  const p = item.json || {};
  const postId = p.post_id ?? p.id ?? null;
  if (!postId) continue;

  if (!byPost.has(postId)) {
    byPost.set(postId, {
      post_id: postId,

      // common context
      row_number: toNumOrNull(p.row_number),
      now_utc: p.update_last_run_at_utc ?? p._now_utc ?? null,
      now_local: p.update_last_run_at ?? p._now ?? null,
      last_run_key: p.update_last_run_key ?? p._run_key ?? null,
      plan_run_at: p.update_plan_run_at ?? p._plan_run_at ?? null,

      // flags
      send_tg: toBoolOrNull(p.send_tg),
      send_vk: toBoolOrNull(p.send_vk),
      send_max: toBoolOrNull(p.send_max),

      // collector results
      tg_seen: false,
      tg_ok: null,
      tg_ok_count: null,
      tg_fail_count: null,
      tg_total: null,

      vk_seen: false,
      vk_ok: null,
      vk_ok_count: null,
      vk_fail_count: null,
      vk_total: null,

      max_seen: false,
      max_ok: null,
      max_ok_count: null,
      max_fail_count: null,
      max_total: null,

      // logs
      prev_error: p.error_prev ?? null,
      tg_update_error: null,
      vk_update_error: null,
      max_update_error: null,
    });
  }

  const agg = byPost.get(postId);

  // keep row_number if missing
  if (agg.row_number === null || agg.row_number === undefined) {
    agg.row_number = toNumOrNull(p.row_number);
  }

  // keep best timestamps/keys/plan
  agg.now_utc = pickFirstNonEmpty(agg.now_utc, p.update_last_run_at_utc, p._now_utc);
  agg.now_local = pickFirstNonEmpty(agg.now_local, p.update_last_run_at, p._now);
  agg.last_run_key = pickFirstNonEmpty(agg.last_run_key, p.update_last_run_key, p._run_key);
  agg.plan_run_at = pickFirstNonEmpty(agg.plan_run_at, p.update_plan_run_at, p._plan_run_at);

  // capture send flags if present anywhere
  const st = toBoolOrNull(p.send_tg);
  const sv = toBoolOrNull(p.send_vk);
  const sm = toBoolOrNull(p.send_max);
  if (st !== null) agg.send_tg = st;
  if (sv !== null) agg.send_vk = sv;
  if (sm !== null) agg.send_max = sm;

  // capture prev_error if present
  if (p.error_prev !== undefined && p.error_prev !== null) agg.prev_error = p.error_prev;

  // Determine if this is TG/VK/MAX collector item
  if (isTgCollectorItem(p) || p._all_ok !== undefined) {
    agg.tg_seen = true;
    if (typeof p._all_ok === 'boolean') agg.tg_ok = p._all_ok;
    agg.tg_ok_count = toNumOrNull(p._sent_ok);
    agg.tg_fail_count = toNumOrNull(p._sent_fail);
    agg.tg_total = toNumOrNull(p._sent_total);
    if (p.update_error) agg.tg_update_error = safeStr(p.update_error);
  }

  if (isVkCollectorItem(p) || p._vk_all_ok !== undefined) {
    agg.vk_seen = true;
    if (typeof p._vk_all_ok === 'boolean') agg.vk_ok = p._vk_all_ok;
    agg.vk_ok_count = toNumOrNull(p._vk_sent_ok);
    agg.vk_fail_count = toNumOrNull(p._vk_sent_fail);
    agg.vk_total = toNumOrNull(p._vk_sent_total);
    if (p.update_error) agg.vk_update_error = safeStr(p.update_error);
  }

  if (isMaxCollectorItem(p) || p._max_all_ok !== undefined) {
    agg.max_seen = true;
    if (typeof p._max_all_ok === 'boolean') agg.max_ok = p._max_all_ok;
    agg.max_ok_count = toNumOrNull(p._max_sent_ok);
    agg.max_fail_count = toNumOrNull(p._max_sent_fail);
    agg.max_total = toNumOrNull(p._max_sent_total);
    if (p.update_error) agg.max_update_error = safeStr(p.update_error);
  }

  // If item isn't clearly a collector, but has update_error, keep as prev_error fallback
  if (!agg.tg_update_error && !agg.vk_update_error && !agg.max_update_error && p.update_error) {
    agg.prev_error = p.update_error;
  }
}

// Helper: last line of a log string
function lastLine(s) {
  if (!s) return '';
  const lines = String(s).split('\n').map(x => x.trim()).filter(Boolean);
  return lines.length ? lines[lines.length - 1] : '';
}

function ensureNowIso(v) {
  const s = safeStr(v).trim();
  return s ? s : new Date().toISOString();
}

const out = [];

for (const agg of byPost.values()) {
  // Decide requirements:
  // If send_* unknown, infer from presence of collector items.
  const reqTg = (agg.send_tg === null || agg.send_tg === undefined) ? agg.tg_seen : agg.send_tg;
  const reqVk = (agg.send_vk === null || agg.send_vk === undefined) ? agg.vk_seen : agg.send_vk;
  const reqMax = (agg.send_max === null || agg.send_max === undefined) ? agg.max_seen : agg.send_max;

  // Determine per-channel ok:
  const tgOk = reqTg ? (agg.tg_ok === true) : true;
  const vkOk = reqVk ? (agg.vk_ok === true) : true;
  const maxOk = reqMax ? (agg.max_ok === true) : true;

  const allOk = tgOk && vkOk && maxOk;

  // Build final error:
  let newError = null;

  const tgLine = lastLine(agg.tg_update_error);
  const vkLine = lastLine(agg.vk_update_error);
  const maxLine = lastLine(agg.max_update_error);

  if (tgLine) newError = appendLog(newError, tgLine);
  if (vkLine) newError = appendLog(newError, vkLine);
  if (maxLine) newError = appendLog(newError, maxLine);

  if (!newError) {
    newError = `[INFO] ${safeStr(agg.now_utc || new Date().toISOString())} no logs from collectors`;
  }

  // IMPORTANT CHANGE:
  // We always write last_run_* and plan_run_at, even if allOk=false.
  // This prevents repeated retries every 5 minutes for the same runKey.
  const finalNowUtc = ensureNowIso(agg.now_utc);
  const finalNowLocal = pickFirstNonEmpty(agg.now_local, agg._now, null); // keep whatever local string collectors provided
  const finalRunKey = pickFirstNonEmpty(agg.last_run_key, null);
  const finalPlanRunAt = pickFirstNonEmpty(agg.plan_run_at, null);

  out.push({
    json: {
      post_id: agg.post_id,
      row_number: agg.row_number,

      _all_ok: allOk,

      // expose requirements/statuses
      _req_tg: reqTg,
      _req_vk: reqVk,
      _req_max: reqMax,

      _tg_ok: agg.tg_ok,
      _vk_ok: agg.vk_ok,
      _max_ok: agg.max_ok,

      // counts
      _tg_sent_ok: agg.tg_ok_count,
      _tg_sent_fail: agg.tg_fail_count,
      _tg_sent_total: agg.tg_total,

      _vk_sent_ok: agg.vk_ok_count,
      _vk_sent_fail: agg.vk_fail_count,
      _vk_sent_total: agg.vk_total,

      _max_sent_ok: agg.max_ok_count,
      _max_sent_fail: agg.max_fail_count,
      _max_sent_total: agg.max_total,

      // Sheets update fields (ALWAYS write, even on error)
      update_last_run_at_utc: finalNowUtc,
      update_last_run_at: finalNowLocal ?? null,
      update_last_run_key: finalRunKey ?? null,
      update_plan_run_at: finalPlanRunAt ?? null,

      update_error: newError,
    },
  });
}

return out;

// ответы из C1 (c1[i].json.data = строка)
const c1 = $items('Узел C1');

// строки из Merge7 (idx, mediaType, url, + контекст: chat_id/text/max/_run_key_channel/...)
const m1 = $items('Merge7');

// ответы из A1 (там token для video)
const a1 = $items('Узел A1');

return c1.map((c, i) => {
  const resp = String(c.json?.data ?? '');
  const base = m1[i]?.json ?? {};
  const a1token = a1[i]?.json?.token ?? null;

  // VIDEO: токен берём из A1
  if (base.mediaType === 'video') {
    return {
      json: {
        // ВАЖНО: сохраняем контекст
        ...base,

        // и перезаписываем token корректным
        token: a1token,
      }
    };
  }

  // IMAGE: токен вытаскиваем из строки ответа C1
  let token = null;
  const m = resp.match(/"token"\s*:\s*"([^"]+)"/);
  if (m) token = m[1];

  return {
    json: {
      // ВАЖНО: сохраняем контекст
      ...base,

      // и перезаписываем token
      token,
    }
  };
});

/**
 * Build MAX /messages payload PER STORE (PER chat_id)
 *
 * Input: items after Code in JavaScript4
 *   (там уже есть token для каждого media, и проброшен контекст store_id/chat_id/text/order_links/...)
 *
 * Output: MANY items — по одному на точку/чат.
 */

const rows = $input.all().map(x => x.json ?? {});

// --- helpers ---
function cleanLine(s) {
  return String(s ?? '').replace(/[\uFEFF\u200B\u200C\u200D\u2060\u00AD]/g, '').trim();
}

function stripGoodMorningNavigationMax(text) {
  // Убираем ТОЛЬКО конечную строку "!!Навигация" (с возможными пробелами)
  // и не трогаем текст, если "!!Навигация" где-то внутри.
  let t = String(text ?? '').replace(/\r\n/g, '\n');
  t = t.replace(/\n\s*!!Навигация\s*$/u, '');
  return t.trim();
}

function ensureGoodMorningOrderButton(orderLinks) {
  // Возвращаем новый массив order_links, где есть кнопка "ЗАКАЗАТЬ В КООПТОРГЕ" -> https://koptorg.ru
  const base = Array.isArray(orderLinks) ? orderLinks : [];
  const btnText = 'ЗАКАЗАТЬ В КООПТОРГЕ';
  const btnUrl = 'https://koptorg.ru';

  const exists = base.some(b => {
    const t = cleanLine(b?.text);
    const u = cleanLine(b?.url);
    return t.toLowerCase() === btnText.toLowerCase() && u === btnUrl;
  });

  if (exists) return base;

  return [...base, { text: btnText, url: btnUrl }];
}

function normButtons(orderLinks) {
  const arr = Array.isArray(orderLinks) ? orderLinks : [];
  const clean = arr
    .map(b => ({
      text: cleanLine(b?.text),
      url: cleanLine(b?.url),
    }))
    .filter(b => b.text && b.url && /^https?:\/\//i.test(b.url));

  if (!clean.length) return null;

  // MAX: безопасно по 1 кнопке в ряд
  return {
    type: "inline_keyboard",
    payload: {
      buttons: clean.map(b => ([{ type: "link", text: b.text, url: b.url }]))
    }
  };
}

function groupKey(p) {
  const postId = p.post_id ?? p.id ?? '';
  const storeId = p.store_id ?? '';
  const chatId = p.chat_id ?? p.max?.channel_id ?? p.max_channel_id ?? '';
  return `${postId}::${storeId}::${chatId}`;
}

// --- group by store/chat ---
const groups = new Map();
for (const p of rows) {
  const k = groupKey(p);
  if (!groups.has(k)) groups.set(k, []);
  groups.get(k).push(p);
}

// --- build one message per group ---
const out = [];

for (const [k, items] of groups.entries()) {
  // сортировка по idx чтобы медиа были в правильном порядке
  items.sort((a, b) => (a.idx ?? 0) - (b.idx ?? 0));

  const first = items[0] || {};
  const chatId =
    first.chat_id ??
    first.max?.channel_id ??
    first.max_channel_id ??
    null;

  if (!chatId) {
    // если вдруг нет chat_id — просто пропускаем, чтобы не падать
    continue;
  }

  // --- TEXT (MAX) ---
  let text = (first.max?.text ?? first.text ?? '').toString();

  // FIX #1: убрать "!!Навигация" ТОЛЬКО для GOODMORNING в ветке MAX
  if (first._goodmorning === true) {
    text = stripGoodMorningNavigationMax(text);
  }

  // --- media attachments (tokenized) ---
  const mediaAttachments = items
    .filter(x => x.token && x.mediaType)
    .map(x => ({
      type: x.mediaType, // "image" | "video"
      payload: { token: x.token }
    }));

  // --- buttons / inline keyboard ---
  // FIX #2: для GOODMORNING добавляем кнопку "ЗАКАЗАТЬ В КООПТОРГЕ" -> https://koptorg.ru
  const effectiveOrderLinks =
    (first._goodmorning === true)
      ? ensureGoodMorningOrderButton(first.order_links)
      : first.order_links;

  const keyboardAttachment = normButtons(effectiveOrderLinks);

  const attachments = [...mediaAttachments];
  if (keyboardAttachment) attachments.push(keyboardAttachment);

  out.push({
    json: {
      // ✅ сохраняем ВЕСЬ контекст (важно для Collect MAX results / финального мерджа)
      ...first,

      // ✅ поля отправки
      chat_id: chatId,
      text,
      format: "markdown",
      notify: true,
      attachments,

      // (опционально, но полезно для дебага) — что реально пошло в кнопки
      // _max_effective_order_links: effectiveOrderLinks,
    }
  });
}

return out;

// MAX code after switch (UPDATED)
// Вход: items из ветки channel=max после Expand per store (т.е. по одному item на магазин)
// Приоритет источников медиа:
// 1) max_media_group / max_media + max_op (из Expand per store) ✅
// 2) fallback: media_raw строка "ф|url ... в|url ..."          (если вдруг прилетает)
//
// Выход: items для A1/B1/C1 (idx, mediaType, url) + проброс chat_id/text
//
// FIX: раньше было $input.first() → терялись остальные магазины.
// Теперь обрабатываем ВСЕ входные items.

const inputs = $input.all().map(i => i.json ?? {});

// Нормализуем медиа из “нового” формата
const normMediaObj = (m) => {
  if (!m) return null;

  // допускаем форматы:
  // { type:'image'|'video', media:'url' }
  // { type:'image'|'video', url:'url' }
  // { mediaType:'image'|'video', url:'url' }
  const type = (m.type ?? m.mediaType ?? '').toString().trim().toLowerCase();
  const url  = (m.media ?? m.url ?? '').toString().trim();

  if (!url) return null;

  const mediaType = (type === 'video') ? 'video' : 'image'; // default to image
  return { mediaType, url };
};

function buildForOne(src) {
  const chatId =
    src.chat_id ??
    src.max?.channel_id ??
    src.max_channel_id ??
    null;

  const text = (src.max?.text ?? src.text ?? '').toString();

  // max_op: message | image | video | media_group
  const maxOp = (src.max_op ?? '').toString().trim().toLowerCase();

  // 1) Новый путь: max_media_group
  let mediaList = [];
  if (Array.isArray(src.max_media_group) && src.max_media_group.length > 0) {
    for (const m of src.max_media_group) {
      const nm = normMediaObj(m);
      if (nm) mediaList.push(nm);
    }
  }

  // 2) Новый путь: одиночное медиа
  if (mediaList.length === 0 && src.max_media) {
    const singleType = (maxOp === 'video') ? 'video' : 'image';
    const url = (src.max_media ?? '').toString().trim();
    if (url) mediaList.push({ mediaType: singleType, url });
  }

  // 3) Fallback: парсинг media_raw "в|url / ф|url"
  if (mediaList.length === 0) {
    const mediaRaw =
      (src.media_raw ?? src.max_media_raw ?? src._raw?.media_url ?? src._raw?.media_raw ?? '').toString();

    const re = /(^|[\s\r\n]+)\+?\s*([вфvf])\|(\S+)/gi;
    let m;
    while ((m = re.exec(mediaRaw)) !== null) {
      const prefix = (m[2] || '').toLowerCase();
      const url = (m[3] || '').toString().trim();
      if (!url) continue;

      const mediaType = (prefix === 'в' || prefix === 'v') ? 'video' : 'image';
      mediaList.push({ mediaType, url });
    }
  }

  // Если медиа по смыслу не нужно (message) или реально отсутствует — отдаём 1 item
  if (maxOp === 'message' || mediaList.length === 0) {
    return [{
      json: {
        ...src,
        chat_id: chatId,
        text,
        idx: 0,
        mediaType: null,
        url: null,
        _max_no_media: true,
        _max_media_count: 0,
        _max_media_source:
          (Array.isArray(src.max_media_group) && src.max_media_group.length > 0) ? 'max_media_group' :
          (src.max_media ? 'max_media' :
          ((src.media_raw || src._raw?.media_url || src._raw?.media_raw) ? 'media_raw_fallback' : 'none')),
      },
    }];
  }

  // Дедуп URL + сборка items
  const seen = new Set();
  const out = [];
  let idx = 0;

  for (const it of mediaList) {
    const key = `${it.mediaType}|${it.url}`;
    if (seen.has(key)) continue;
    seen.add(key);

    out.push({
      json: {
        ...src,

        // пробрасываем нужное для Send Message
        chat_id: chatId,
        text,

        // то, что нужно твоим Узлам A1/B1/C1
        idx,
        mediaType: it.mediaType,
        url: it.url,

        _max_no_media: false,
      },
    });

    idx++;
  }

  if (out.length === 0) {
    return [{
      json: {
        ...src,
        chat_id: chatId,
        text,
        idx: 0,
        mediaType: null,
        url: null,
        _max_no_media: true,
        _max_media_count: 0,
        _max_media_source:
          (Array.isArray(src.max_media_group) && src.max_media_group.length > 0) ? 'max_media_group' :
          (src.max_media ? 'max_media' :
          ((src.media_raw || src._raw?.media_url || src._raw?.media_raw) ? 'media_raw_fallback' : 'none')),
      },
    }];
  }

  // Полезный дебаг
  const source =
    (Array.isArray(src.max_media_group) && src.max_media_group.length > 0) ? 'max_media_group' :
    (src.max_media ? 'max_media' :
    ((src.media_raw || src._raw?.media_url || src._raw?.media_raw) ? 'media_raw_fallback' : 'none'));

  for (const o of out) {
    o.json._max_media_count = out.length;
    o.json._max_media_source = source;
  }

  return out;
}

// flatten results for all stores
return inputs.flatMap(buildForOne);

/**
 * Collect MAX results per post_id (Function node version) — FIXED
 *
 * Fixes:
 *  1) reason no longer shows "[object Object]" (safeJson)
 *  2) success detector recognizes MAX success by presence of message.body.mid (or body.mid)
 */

const inItems = items;

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v);
}

function safeJson(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  try {
    const s = JSON.stringify(v);
    return s.length > 500 ? s.slice(0, 500) + '…' : s;
  } catch {
    return String(v);
  }
}

function toNumOrNull(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function toBoolOrNull(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  const s = String(v).trim().toLowerCase();
  if (s === '') return null;
  if (s === '1' || s === 'true' || s === 'yes' || s === 'y') return true;
  if (s === '0' || s === 'false' || s === 'no' || s === 'n') return false;
  return null;
}

function appendLog(existing, line) {
  const base = (existing ?? '').toString().trim();
  if (!base) return line;
  return base + '\n' + line;
}

function pickFirstNonEmpty(...vals) {
  for (const v of vals) {
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return v;
  }
  return null;
}

function nowIso() {
  return new Date().toISOString();
}

// Heuristic success detector (MAX-aware)
function isOk(p) {
  // MAX success usually includes message.body.mid (or body.mid)
  const mid = p?.message?.body?.mid ?? p?.body?.mid ?? null;
  if (mid) return true;

  const sc =
    p.statusCode ??
    p.status_code ??
    p.httpStatus ??
    p.http_status ??
    null;

  if (typeof sc === 'number') return sc >= 200 && sc < 300;

  if (p.ok === true || p.success === true) return true;

  if (p.error || p.err) return false;

  const data = p.data ?? p.body ?? p.response ?? null;
  if (data && typeof data === 'object') {
    if (data.error || data.errors) return false;
    if (data.ok === true || data.success === true) return true;
  }

  return false;
}

function extractErr(p) {
  const candidates = [
    p.error?.message,
    p.error?.description,
    p.err?.message,
    p.message,
    p.data?.error?.message,
    p.data?.error_description,
    p.body?.error?.message,
    p.statusMessage,
  ].filter(Boolean);

  if (candidates.length) return candidates[0]; // may be string/object

  // If MAX returned error-ish structure in message/body, keep it
  if (p?.message) return p.message;
  if (p?.body) return p.body;

  return p; // last-resort, will be stringified by safeJson
}

// Group per post_id
const byPost = new Map();

for (const item of inItems) {
  const p = item.json || {};
  const postId = p.post_id ?? p.id ?? null;
  if (!postId) continue;

  if (!byPost.has(postId)) {
    byPost.set(postId, {
      post_id: postId,

      row_number: toNumOrNull(p.row_number),
      now_utc: p.update_last_run_at_utc ?? p._now_utc ?? null,
      now_local: p.update_last_run_at ?? p._now ?? null,
      last_run_key: p.update_last_run_key ?? p._run_key ?? null,
      plan_run_at: p.update_plan_run_at ?? p._plan_run_at ?? null,

      send_max: toBoolOrNull(p.send_max),

      prev_error: p.error_prev ?? p.update_error ?? null,

      total: 0,
      ok: 0,
      fail: 0,
      first_fail_reason: null,
    });
  }

  const agg = byPost.get(postId);

  if (agg.row_number === null || agg.row_number === undefined) {
    agg.row_number = toNumOrNull(p.row_number);
  }

  agg.now_utc = pickFirstNonEmpty(agg.now_utc, p.update_last_run_at_utc, p._now_utc);
  agg.now_local = pickFirstNonEmpty(agg.now_local, p.update_last_run_at, p._now);
  agg.last_run_key = pickFirstNonEmpty(agg.last_run_key, p.update_last_run_key, p._run_key);
  agg.plan_run_at = pickFirstNonEmpty(agg.plan_run_at, p.update_plan_run_at, p._plan_run_at);

  const sm = toBoolOrNull(p.send_max);
  if (sm !== null) agg.send_max = sm;

  agg.total += 1;

  const ok = isOk(p);
  if (ok) agg.ok += 1;
  else {
    agg.fail += 1;
    if (!agg.first_fail_reason) agg.first_fail_reason = extractErr(p);
  }
}

const out = [];

for (const agg of byPost.values()) {
  const reqMax = (agg.send_max === null || agg.send_max === undefined) ? true : agg.send_max;
  const allOk = reqMax ? (agg.fail === 0) : true;

  const ts = safeStr(agg.now_utc || nowIso());
  const line = allOk
    ? `[MAX] ${ts} ok ${agg.ok}/${agg.total}`
    : `[MAX] ${ts} FAIL ok ${agg.ok}/${agg.total} reason: ${safeJson(agg.first_fail_reason || 'unknown')}`;

  const newError = appendLog(agg.prev_error, line);

  out.push({
    json: {
      post_id: agg.post_id,
      row_number: agg.row_number,

      send_max: reqMax,

      _max_sent_total: agg.total,
      _max_sent_ok: agg.ok,
      _max_sent_fail: agg.fail,
      _max_all_ok: allOk,

      update_last_run_at_utc: agg.now_utc ?? null,
      update_last_run_at: agg.now_local ?? null,
      update_last_run_key: agg.last_run_key ?? null,
      update_plan_run_at: agg.plan_run_at ?? null,

      update_error: newError,
    }
  });
}

return out;

// Restore context after A1

const prev = $items('MAX code after switch'); // имя ноды ДО A1
const current = $input.all();

return current.map((item, i) => {
